import { type ReactElement, useCallback, useState, type JSX } from 'react';

import type { TimeframeSelectorState } from '../../../core/time/timeframeStore/timeframeSelector.types.js';
import type { FormControlBaseProps } from '../../../core/types/form-control-props.js';
import { Flex } from '../../../layouts/flex/Flex.js';
import { Tooltip } from '../../../overlays/tooltip/Tooltip.js';
import { Text } from '../../../typography/text/Text.js';
import { useTooltipMessages } from '../hooks/useTooltipMessages.js';

//#region Typings
interface TimeframeSelectorTooltipProps extends FormControlBaseProps {
  /** Single child of the tooltip considered to trigger the tooltip element. */
  children: ReactElement;
  /** The value of the timeframe selector, containing the 'from' and 'to' timeframe details. */
  value: TimeframeSelectorState['timeframeSelectorTimeframe'];
  /** Displayed Value at the trigger. */
  displayValue: string | JSX.Element;
}
//#endregion

/**
 * TimeframeSelectorTooltip component to show the displayValue, start, end and duration in a tooltip.
 * @internal
 */
export const TimeframeSelectorTooltip = (
  props: TimeframeSelectorTooltipProps,
) => {
  const {
    value,
    disabled,
    displayValue,
    children,
  }: TimeframeSelectorTooltipProps = props;

  const [tooltipTimeValues, setTooltipTimeValues] = useState({
    tooltipFormattedTimeValueStart: '',
    tooltipFormattedTimeValueEnd: '',
  });

  const {
    tooltipFormattedTimeValueStart,
    tooltipFormattedTimeValueEnd,
    timeframeDuration,
    isAbsoluteTimeframe,
    isInvalid,
  } = useTooltipMessages(value);

  const onOpenTooltip = useCallback(
    (open: boolean) => {
      if (open) {
        setTooltipTimeValues({
          tooltipFormattedTimeValueStart,
          tooltipFormattedTimeValueEnd,
        });
      }
    },
    [tooltipFormattedTimeValueEnd, tooltipFormattedTimeValueStart],
  );

  return (
    <Tooltip
      text={
        <Flex flexDirection="column" gap={4}>
          <Flex gap={0} flexDirection="column">
            {
              // displayValue is a string when a preset item name is used.
              (typeof displayValue === 'string' || !isAbsoluteTimeframe) && (
                <Text textStyle="small-emphasized">{displayValue}</Text>
              )
            }
            <Text textStyle="small">
              {tooltipTimeValues.tooltipFormattedTimeValueStart}
            </Text>
            <Text textStyle="small">
              {tooltipTimeValues.tooltipFormattedTimeValueEnd}
            </Text>
          </Flex>
          <Flex gap={0} flexDirection="column">
            <Text textStyle="small">{timeframeDuration}</Text>
          </Flex>
        </Flex>
      }
      disabled={disabled || isInvalid}
      onOpenChange={onOpenTooltip}
    >
      {children}
    </Tooltip>
  );
};

(
  TimeframeSelectorTooltip as typeof TimeframeSelectorTooltip & {
    displayName: string;
  }
).displayName = 'TimeframeSelectorTooltip';
